# Azure Government: deploy with ARM template, adjusting endpoints
# Template parameters file for Azure Government deployment

cat > gov-params.json << 'EOF'
{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentParameters.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "location": {
      "value": "usgovvirginia"
    },
    "storageAccountType": {
      "value": "Standard_GRS"   // GRS replicates to USGov Texas — still within Azure Government
    },
    "environment": {
      "value": "AzureUSGovernment"
    }
  }
}
EOF

# Deploy using az deployment group create (same command, different cloud environment)
az cloud set --name AzureUSGovernment
az login --tenant <gov-tenant-id>

az deployment group create \
  --resource-group agency-prod-rg \
  --template-file infra/main.bicep \
  --parameters @gov-params.json

# Note: some service names differ — Azure Monitor workspace in Gov:
# location must be usgovvirginia, usgovtexas, or usgovarizona (not usgovarizona2)
